import{inherits}from"./util.js";import LRUCache from"./structs/LRUCache.js";import{fromKey,getKey}from"./tilecoord.js";const TileCache=function(e){LRUCache.call(this,e)};inherits(TileCache,LRUCache),TileCache.prototype.expireCache=function(e){for(;this.canExpireCache();){const i=this.peekLast();var t=i.tileCoord[0].toString();if(t in e&&e[t].contains(i.tileCoord))break;this.pop().dispose()}},TileCache.prototype.pruneExceptNewestZ=function(){if(0!==this.getCount()){var e=this.peekFirstKey();const t=fromKey(e)[0];this.forEach(function(e){e.tileCoord[0]!==t&&(this.remove(getKey(e.tileCoord)),e.dispose())},this)}};export default TileCache;